import { readFileSync } from "node:fs";
import { join } from "node:path";
import { describe, expect, it } from "vitest";
const SRC_ROOT = join(__dirname, "..", "..", "src");
/**
 * Modules that execute on `runStartDataset`'s call path. Stdout in the
 * streaming model is a parseable JSONL stream (one JSON line per event), so
 * any code reachable from `runStartDataset` MUST NOT write to stdout outside
 * the single approved channel (`emitJson` in startDataset.ts) and MUST NOT
 * use `console.log` (status/log messages go to stderr via `console.error`).
 *
 * If you add a new file that may run under `runStartDataset`, add it here.
 * If you add a new file that the streaming path doesn't touch (e.g. a
 * standalone command), don't add it.
 */
const STREAM_PATH_FILES = [
    "agentEventPoller.ts",
    "browserHandoff.ts",
    "handoffTicketChannel.ts",
    "handoffTickets.ts",
    "analytics.ts",
    "config.ts",
    "browser.ts",
    "loopback.ts",
    "pkce.ts",
    "platform.ts",
    "frontmostApp.ts",
];
const STDOUT_WRITE_RE = /process\.stdout\.write/g;
const CONSOLE_LOG_RE = /\bconsole\.log\b/g;
function readSrc(relPath) {
    return readFileSync(join(SRC_ROOT, relPath), "utf-8");
}
describe("startDataset stdout contract", () => {
    it("startDataset.ts: stdout is written exactly once, by emitJson", () => {
        const src = readSrc("commands/startDataset.ts");
        const writes = src.match(STDOUT_WRITE_RE) ?? [];
        expect(writes.length, "startDataset.ts must contain exactly one process.stdout.write " +
            "(inside emitJson). Anything else pollutes the JSONL stream the " +
            "calling agent parses.").toBe(1);
        expect(src.match(CONSOLE_LOG_RE) ?? [], "startDataset.ts must not use console.log — use console.error for " +
            "human-readable status messages so stdout stays a parseable stream.").toEqual([]);
    });
    for (const file of STREAM_PATH_FILES) {
        it(`${file}: no stdout writers and no console.log`, () => {
            const src = readSrc(file);
            expect(src.match(STDOUT_WRITE_RE) ?? [], `${file} writes to process.stdout — startDataset's stdout is a JSONL ` +
                `stream, so any other writer in the call graph corrupts it. Move ` +
                `the write to stderr or refactor it out of the streaming path.`).toEqual([]);
            expect(src.match(CONSOLE_LOG_RE) ?? [], `${file} uses console.log — replace with console.error so stdout ` +
                `stays a parseable JSONL stream for the agent.`).toEqual([]);
        });
    }
});
